// String implement fmt.Stringer interface.
func (f SupplierOrderField) String() string {
	var str string
	switch f.column {
	case SupplierOrderFieldTenantID.column:
		str = "TENANT_ID"
	case SupplierOrderFieldCreatedAt.column:
		str = "CREATED_AT"
	case SupplierOrderFieldCreatedBy.column:
		str = "CREATED_BY"
	case SupplierOrderFieldUpdatedAt.column:
		str = "UPDATED_AT"
	case SupplierOrderFieldUpdatedBy.column:
		str = "UPDATED_BY"
	case SupplierOrderFieldDeletedAt.column:
		str = "DELETED_AT"
	case SupplierOrderFieldDeletedBy.column:
		str = "DELETED_BY"
	}
	return str
}

// MarshalGQL implements graphql.Marshaler interface.
func (f SupplierOrderField) MarshalGQL(w io.Writer) {
	io.WriteString(w, strconv.Quote(f.String()))
}

// UnmarshalGQL implements graphql.Unmarshaler interface.
func (f *SupplierOrderField) UnmarshalGQL(v interface{}) error {
	str, ok := v.(string)
	if !ok {
		return fmt.Errorf("SupplierOrderField %T must be a string", v)
	}
	switch str {
	case "TENANT_ID":
		*f = *SupplierOrderFieldTenantID
	case "CREATED_AT":
		*f = *SupplierOrderFieldCreatedAt
	case "CREATED_BY":
		*f = *SupplierOrderFieldCreatedBy
	case "UPDATED_AT":
		*f = *SupplierOrderFieldUpdatedAt
	case "UPDATED_BY":
		*f = *SupplierOrderFieldUpdatedBy
	case "DELETED_AT":
		*f = *SupplierOrderFieldDeletedAt
	case "DELETED_BY":
		*f = *SupplierOrderFieldDeletedBy
	default:
		return fmt.Errorf("%s is not a valid SupplierOrderField", str)
	}
	return nil
}

